					case '/': 
					if(val2 == 0) { 
						printf("It is wrong to divide by zero\n");
						return 0;
						}
					else return val1 / val2;
					case '!': return (!val2);
					case '&': return (val1 && val2);
					case '|': return (val1 || val2);
					case EQ: return (val1 == val2)? 1 : 0;
					case NOTEQ: return (val1 != val2)? 1 : 0;
					case NEG: return -val2;
					case JIE: return mem_read(val2,4);
				 }
		}
		return 0;
}

