}


void print_wp() {
	WP *temp = head;
	if(temp == NULL) printf("No watchpoint\n");
	else{
		printf("\tNO\tAddress\t\t\tENABLE\n");
		while(temp!= NULL){
		printf("\t%d\t%s\t%d\n", temp->NO, temp->expr, temp->val);
		temp = temp->next;
	}
	}
}
